@patch(cls_method=True)
async def launch(cls:CDP,
    user_data_dir:str|Path=None, # Profile dir; `~/.cache/fastcdp/profile` if None
    headless:bool=False, # Run without a visible window?
    debug:bool=None, # Print protocol events?
    timeout:int=10, # Seconds to wait for the debug endpoint
    reuse:bool=True, # Connect to an instance already running on this profile? (Else raise)
):
    "Launch the installed Chrome CDP-ready on its own profile dir, and connect to it"
    d = Path(user_data_dir) if user_data_dir else Path.home()/'.cache'/'fastcdp'/'profile'
    d.mkdir(parents=True, exist_ok=True)
    f = d/'DevToolsActivePort'
    if f.exists():
        ci = cdp_conninfo(d=d)
        port = int(ci.split('/', 1)[0])
        if is_port_free(port): f.unlink()   # provably stale: nothing is listening
        elif not reuse: raise RuntimeError(f'{f} names a running Chrome on port {port}; pass reuse=True to connect to it')
        else:
            try: self = await cls.connect(wsconn=ci, debug=debug)
            except (OSError, websockets.WebSocketException) as e: raise RuntimeError(f'port {port} from {f} is in use but not connectable; is something other than Chrome using it?') from e
            self.proc,self.port = None,port
            return self
    args = [f'--user-data-dir={d}', '--remote-debugging-port=0', '--no-first-run', '--no-default-browser-check']
    if headless: args.append('--headless=new')
    proc = await asyncio.create_subprocess_exec(chrome_bin(), *args,
        stdout=asyncio.subprocess.DEVNULL, stderr=asyncio.subprocess.DEVNULL)
    deadline = asyncio.get_event_loop().time() + timeout
    while not f.exists():
        if proc.returncode is not None: raise RuntimeError('Chrome exited at launch (already running on this profile dir?)')
        if asyncio.get_event_loop().time() > deadline: raise TimeoutError('Timed out waiting for Chrome debug endpoint')
        await asyncio.sleep(0.05)
    ci = cdp_conninfo(d=d)
    self = await cls.connect(wsconn=ci, debug=debug)
    self.proc,self.port = proc, int(ci.split('/', 1)[0])
    return self

